import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"黑暗骑士","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/黑暗骑士.md","filePath":"4.资源分区/1.血统与训练/1.生理类/黑暗骑士.md"}'),s={name:"4.资源分区/1.血统与训练/1.生理类/黑暗骑士.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"黑暗骑士",tabindex:"-1"},[p("黑暗骑士 "),r("a",{class:"header-anchor",href:"#黑暗骑士","aria-label":'Permalink to "黑暗骑士"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001D")])])],-1),n('<h1 id="黑暗骑士-1" tabindex="-1">黑暗骑士 <a class="header-anchor" href="#黑暗骑士-1" aria-label="Permalink to &quot;黑暗骑士&quot;">​</a></h1><p>黑暗骑士训练<br> CD+1800<br> 黑暗骑士，亦或者说“蝙蝠侠”，失去了至亲而选择向世界上的罪恶竭力斗争的凡人；与大多数超级英雄不同，黑暗骑士并不拥有超凡力量以帮助他实现自己的目的，他所能够依靠的，只有超乎寻常的坚韧与冷静的头脑。 <br>   身为义警的黑暗骑士虽然是一位制止犯罪的英雄，却亦是违反法律的不法之徒；也正因如此，黑暗骑士更需要坚持其内心的准则。 <br> 强化本训练后，你需要遵循黑暗骑士的准则： <br> 1、不可直接或间接的杀害人类。（人的定义不代表着绝对意义上的纯种人类，变种人、亚人也算作人，由St进行裁定） <br> 2、对处于危险状态下的人竭尽所能去帮助其脱离险境。<br> 3、对恶人应进行镇压并予以应有的惩罚。 【注：准则3中的惩罚不意味着由黑暗骑士进行最终审判，对恶人实行的判决应交由影片内的律法执行机构进行。】 <br> 一旦违反，你将不可避免的失去黑暗骑士训练及其带来的所有好处。<br>  <br> 【蝙蝠洞】：（特殊的，本特性为St选开） <br> 你在进入影片时，总是有一间隐秘的别墅住所作为基地，这间别墅隐秘的连接着蝙蝠洞，只有你知晓开启蝙蝠洞的方式（可以是口令、转动别墅内的某幅画像、吹灭办公桌上的烛台等行为）蝙蝠洞内设置有起居空间、发电机，武器库，飞机库和车库，蝙蝠战衣陈列柜等设施。 其内存放有你所购买的载具、不便携带的物品等，你可以在进入影片前选择将自己已有的物品置于蝙蝠洞内。（这也代表着你本身没有的物品，蝙蝠洞内也并不具有。）</p><p>【蝙蝠灯】：<br>   在进入影片后，黑暗骑士可在影片内的高楼顶层花费二个小时的时间布置一座蝙蝠灯，当蝙蝠灯亮起时，属于黑暗骑士的蝙蝠印记会直射天穹。<br> 蝙蝠灯需要由人手动开启，当蝙蝠灯亮起后，若黑暗骑士处于城市的任何角落，可花费15分钟-1小时（也可能更长）左右的时间前往蝙蝠灯所在的楼顶。<br> 若黑暗骑士在蝙蝠灯亮起时擒获一名甚至多名罪犯，黑暗骑士在影片结束时声望会提升6点。</p><p>【缜密思维】：黑暗骑士冷静的头脑令其对罪犯的蛛丝马迹异常敏感。 黑暗骑士可以对一件被使用过物品、场景中有互动痕迹的物件（可能需要进行搜索行为）等线索进行分析，进而得出与线索直接相关的信息。在没有合适的分析装置前，黑暗骑士只能对物理线索进行分析，你所能获得的信息类型举例如下： <br> 1、根据墙体破坏程度判断使用武器/使用者力量属性。 <br> 2、从血液凝固时间中获得战斗大致发生时间。 <br> 3、从与周遭比略微有所不同的地面推断出这里可能有暗格或者是陷阱。 <br> 4、黑暗骑士从地面搜索获得没入其中的子弹，根据射入角度推测出射击者进行射击的方向。 <br> 5、从一个需要按动键盘输入密码开启的设备上，看出有哪些按键磨损最为严重。（这不代表能直接获得密码。） <br> 6、在一片狼籍的战斗遗留现场中大致分析出参加战斗的人数、作战风格（如：窃贼、土匪作战风格相对杂乱、黑帮更偏向威慑、军队执行任务风格严谨、刺客则将他人悄无声息的暗杀…）<br> 以及其他一系列由St所允许的获取信息手段。 <br> 该能力所获得的信息不代表绝对正确，而仅仅是对客观事物的推测。如果需要对抗，本能力被视为是C级别环境来源的信息回溯能力。 <br> 若搜集到了足够明确的信息，黑暗骑士可根据这些信息来对目标进行追踪检定。<br>  【注：你不能从密码键盘曾经被按动过就对目标进行追踪，它们二者不构成直接关联。】</p><p>【黑夜匿踪】：<br> 黑暗骑士可对科技本质的护甲进行改造：进行一个DC为护甲支线等级*5，周期为天，使用【智力+手艺+制造物品】的延长检定。当延长检定成功后，该护甲被视为改造成功。 <br> 仅当黑暗骑士身着被改造成功的护甲且处于夜晚时，其具有B级别科技本质的反侦察等级。</p><p>【全能武艺】：<br> 黑暗骑士不具有其他超级英雄所特有的各式能力，其所能做的，只有将凡人所能做到的事情磨练至极致，并加以汇总糅合。<br> 黑暗骑士每掌握4个D级别标准动作使用的、以武技/射击/运动作为检定构成技能的攻击招式，便能在一次攻击中额外结合一项D级别招式同时生效，结合招式的攻击需要符合招式生效的前提条件、需求、攻击方式。如果所掌握招式是一次购买习得多个的，则在计算招式数量时，仅计算一半数量的以该方式购买的招式。<br> （如：布鲁斯掌握了108项D级别攻击技艺，理论上他能同时在一次攻击中同时使用27个D级招式，由于他此次攻击方式较为罕见，在检索符合生效前提条件、需求的招式后，只有6项符合应用条件，则此次攻击只能额外结合6项D级招式。）</p><p>【恐惧威慑】：<br> 黑暗骑士拥有着给予施暴者以恐惧的能力，这甚至会令这些罪犯的脑海在往后余生中都留下一个不可抹去的黑色阴影。 <br> 黑暗骑士在夜晚造成伤害时，可以仅造成冲击伤害（这些冲击伤害不会恶化）并同时给予目标等同（计算防御后的）攻击成功数的恐惧异常点数，标准豁免。 <br> 若目标由黑暗骑士造成的恐惧点数而进入【毁灭性后果】，则其在该【毁灭性后果】没有移除前，只要目标进行非正义的暴力行为，其脑海中就会浮现黑暗骑士的身影，这身影可能出现在目标感知范围内的任何地方，目标会不顾一切的远离黑暗骑士的身影，直至目标不再试图实施暴行为止。</p><p>黑暗骑士训练专属物品：</p><p>蝙蝠战衣套件 <br> 黑暗骑士的专用铠甲由蝙蝠面具、蝙蝠斗篷、蝙蝠战甲、蝙蝠腰带、蝙蝠臂甲、蝙蝠战靴组合而成。这些物品均为科技本质。</p><p>蝙蝠战甲<br> C+1000<br> 这件黑色的紧身战衣在胸口处印有椭圆形的蝙蝠印记，由特殊纤维编织而成的内衬可以有效抵挡子弹与利刃的所造成的伤害。 <br> 轻甲 <br> 盔甲防御：10/10【防弹】 <br> 黑暗骑士受到物理伤害时，可将此次攻击中至多8点伤害向下转化一级（韧性-严重-冲击-完好）。<br> 当你穿戴该套装下的六种装备后，蝙蝠战甲转化的伤害改为向下转化二级，且能转化除精神伤害以外的所有伤害。</p><p>蝙蝠斗篷<br> C+1000<br> 占据斗篷位 <br> 蝙蝠斗篷的边缘由特制的弹性尼龙材料编织的柔性连接结构，令这件斗篷起到了类似滑翔伞的作用。这使得黑暗骑士在从高空落下时非但不会下坠，反而能将下落的重力势能转化为在夜空中滑翔的动能。此外这件斗篷还能对范围伤害起到一定的保护作用。 <br> 只要不是在完全无风的环境下，黑暗骑士在空中时便获得机动性为【普通】的飞行能力。 以该方式进行飞行，使用者的垂直高度依旧会下降10米。<br> 在落地时黑暗骑士只要展开斗篷就不受坠落伤害的影响。<br> 黑暗骑士的盔甲防御增加4点。 <br> 黑暗骑士获得3点【封闭】。</p><p>蝙蝠面具<br> D+500 <br> 这件在头盔两侧有着尖锐突起的黑色合金铸成的半封闭面具在结构上仅会漏出穿戴者的下巴，能良好的保护穿戴者。 <br> 占据头盔位 <br> 穿戴者获得黑暗视觉，并免疫耳鸣异常点数所带来的减值。 <br> 穿戴者免疫由呼吸道途径摄入的C级别毒素/药物来源的负面效果。 <br> 对穿戴者头部进行的部位攻击需要承受3点额外的部位减值。 <br> 蝙蝠面具自带一个标准通信装置，用于联系黑暗骑士的队友或者是智能装备。</p><p>蝙蝠腰带<br> D+500<br> 该腰带的中心有一个方形的蝙蝠印章，也许你能从这件布满大大小小暗格的腰带上找到所有含有【蝙蝠】字段的小型物件？ 在携带体积不大于2的物品时，黑暗骑士总是视为具有足够的体积携带这些物品，你至多在蝙蝠腰带上携带8种不同的物品。 腰带上还搭配有微型计算机，通过连接蝙蝠面具、蝙蝠臂甲，黑暗骑士可以在不需要肢体参与（仍需要消耗相应动作）的情况下进行电脑操作、骇入网络的行为，黑暗骑士在进行类似的器用检定上获得4点器械加值。 此外，腰带正前方还拥有一个微型摄像设备，可以对黑暗骑士的正前方进行录制。</p><p>蝙蝠臂甲<br> D+500<br> 这件臂甲会为黑暗骑士提供有效的手部防护，并在必要时可以充当武器以帮助黑暗骑士进行战斗。<br> 臂甲上同时安装有小型分析仪器与投影设备 。<br> 黑暗骑士在使用手臂肢体进行格挡防御时，额外获得3点盔甲防御。<br> 臂甲上可弹出利刃，这视为武器伤害为3L的拳套。 <br> 臂甲上装有小型的分析装置，现在黑暗骑士使用【缜密思维】分析线索时可对药物/毒素、疾病来源的化学物质进行分析。 <br> （如：黑暗骑士对稻草人所散播的恐惧毒气进行分析，会得到该物质会导致吸入者受到恐惧异常点数的信息。） <br> 臂甲上的投影设备可清晰投影出蝙蝠腰带上微型电脑的内容。</p><p>蝙蝠战靴 <br> D+500<br> 占据鞋袜位 这件装有吸附装置的黑色战靴可以帮助黑暗骑士在任何墙面上如履平地的奔行。 <br> 穿戴者可以在垂直平面上照常进行奔跑，并无视D级别困难地形的影响。 <br> 在应对会使穿戴者被迫移动的负面效果时，减少10米移动距离。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const f=e(s,[["render",o]]);export{D as __pageData,f as default};
